#include <iostream>
#include <algorithm>

using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    long long a, b, c;
    cin >> a >> b >> c;

    // Sort so that c is the largest side
    if (a > c) swap(a, c);
    if (b > c) swap(b, c);
    // now a <= b <= c not strictly needed, but ensure a <= b
    if (a > b) swap(a, b);

    // Compare squared lengths
    long long sum_sq = a * a + b * b;
    long long c_sq = c * c;

    if (sum_sq == c_sq) {
        cout << "Right\n";
    } else if (sum_sq > c_sq) {
        cout << "Acute\n";
    } else {
        cout << "Obtuse\n";
    }

    return 0;
}
